/* Generated by Trae Work */
(function () {
  'use strict';

  // 从 CSS 变量读取颜色
  var cs = getComputedStyle(document.documentElement);
  var colors = {
    bg: cs.getPropertyValue('--bg').trim(),
    bg2: cs.getPropertyValue('--bg2').trim(),
    ink: cs.getPropertyValue('--ink').trim(),
    muted: cs.getPropertyValue('--muted').trim(),
    accent: cs.getPropertyValue('--accent').trim(),
    accent2: cs.getPropertyValue('--accent2').trim(),
    rule: cs.getPropertyValue('--rule').trim()
  };

  var data = window.__DATA || [];

  // 月份标签
  var months = data.map(function (d) {
    return d.year + '-' + String(d.month).padStart(2, '0');
  });

  var kwhList = data.map(function (d) { return d.kwh; });
  var costList = data.map(function (d) { return d.cost; });
  var peakList = data.map(function (d) { return d.peak_kwh; });
  var valleyList = data.map(function (d) { return d.valley_kwh; });

  // 公共配置
  var baseOption = {
    animation: false,
    renderer: 'svg',
    tooltip: {
      appendToBody: true,
      trigger: 'axis',
      backgroundColor: colors.bg2,
      borderColor: colors.rule,
      textStyle: { color: colors.ink }
    },
    grid: {
      left: '10%',
      right: '5%',
      top: '12%',
      bottom: '15%'
    },
    xAxis: {
      type: 'category',
      data: months,
      axisLabel: {
        color: colors.muted,
        rotate: months.length > 8 ? 30 : 0
      },
      axisLine: { lineStyle: { color: colors.rule } },
      axisTick: { lineStyle: { color: colors.rule } }
    },
    yAxis: {
      type: 'value',
      axisLabel: { color: colors.muted },
      splitLine: { lineStyle: { color: colors.rule, type: 'dashed' } },
      axisLine: { show: false }
    }
  };

  // 图表1: 月度电费柱状图
  var costChart = echarts.init(document.getElementById('chart-monthly-cost'), null, { renderer: 'svg' });
  costChart.setOption(Object.assign({}, baseOption, {
    tooltip: Object.assign({}, baseOption.tooltip, {
      formatter: function (params) {
        return params[0].axisValue + '<br/>' +
          '<span style="color:' + colors.accent2 + '">&#9632;</span> 电费: ' +
          params[0].value.toFixed(2) + ' 元';
      }
    }),
    series: [{
      name: '电费',
      type: 'bar',
      data: costList,
      itemStyle: {
        color: colors.accent2,
        borderRadius: [4, 4, 0, 0]
      },
      barMaxWidth: 36
    }]
  }));
  window.addEventListener('resize', function () { costChart.resize(); });

  // 图表2: 月度电量折线图（带面积填充）
  var kwhChart = echarts.init(document.getElementById('chart-monthly-kwh'), null, { renderer: 'svg' });
  kwhChart.setOption(Object.assign({}, baseOption, {
    tooltip: Object.assign({}, baseOption.tooltip, {
      formatter: function (params) {
        return params[0].axisValue + '<br/>' +
          '<span style="color:' + colors.accent + '">&#9679;</span> 电量: ' +
          params[0].value + ' kWh';
      }
    }),
    series: [{
      name: '电量',
      type: 'line',
      data: kwhList,
      smooth: true,
      symbol: 'circle',
      symbolSize: 6,
      lineStyle: { color: colors.accent, width: 2 },
      itemStyle: { color: colors.accent },
      areaStyle: {
        color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [
          { offset: 0, color: 'rgba(56,189,248,0.35)' },
          { offset: 1, color: 'rgba(56,189,248,0.02)' }
        ])
      }
    }]
  }));
  window.addEventListener('resize', function () { kwhChart.resize(); });

  // 图表3: 峰谷电量堆叠柱状图
  var pvChart = echarts.init(document.getElementById('chart-peak-valley'), null, { renderer: 'svg' });
  pvChart.setOption(Object.assign({}, baseOption, {
    legend: {
      data: ['峰电量', '谷电量'],
      textStyle: { color: colors.muted },
      top: 0,
      right: 0
    },
    tooltip: Object.assign({}, baseOption.tooltip, {
      formatter: function (params) {
        var html = params[0].axisValue + '<br/>';
        params.forEach(function (p) {
          var color = p.seriesName === '峰电量' ? colors.accent2 : colors.accent;
          html += '<span style="color:' + color + '">&#9632;</span> ' +
            p.seriesName + ': ' + p.value + ' kWh<br/>';
        });
        return html;
      }
    }),
    xAxis: Object.assign({}, baseOption.xAxis, {
      type: 'category',
      data: months
    }),
    series: [
      {
        name: '峰电量',
        type: 'bar',
        stack: 'pv',
        data: peakList,
        itemStyle: { color: colors.accent2, borderRadius: [4, 4, 0, 0] },
        barMaxWidth: 36
      },
      {
        name: '谷电量',
        type: 'bar',
        stack: 'pv',
        data: valleyList,
        itemStyle: { color: colors.accent },
        barMaxWidth: 36
      }
    ]
  }));
  window.addEventListener('resize', function () { pvChart.resize(); });

})();
